#include<bits/stdc++.h>
using namespace std;
int a[100000][2], b[10001], x,h,art;
void f(int n) {
	if(x<n){
		art++;
		return;
	}
	if (b[a[n][0]] != 1) {
		b[a[n][0]] = 1;
		f(n + 1);
		b[a[n][0]] = 0;
	}

	if (b[a[n][1]] != 1) {
		b[a[n][1]] = 1;
		f(n + 1);
		b[a[n][1]] = 0;
	}

	return;
}

int main() {
	cin >> x;
	for (int i = 0; i < x; i++) {
		cin >> a[i][0] >> a[i][1];
	}
	f(0);
	cout<<art/2;
	return 0;
}
